#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
#define drep(a,b,c) for(register int c=(a);c>=(b);--c)
#define N 1000005
using namespace std;
const int Mod=19940417;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline long long qpow(int x,int k){long long res=1;while(k){if(k&1)res=res*x%Mod;x=x*x%Mod;k=k>>1;}return res;}
struct node{int x,y;inline bool operator<(const node &a){return x<a.x;}}a[N];
map<int,bool>q; long long dp[N][2];
signed main()
{
	int mx=read(),qn=read(),n=1,mxn=0;
	a[1].x=a[1].y=0;q[0]=q[mx]=1;dp[1][1]=1;rep(1,qn,i)
	{
		int x=read(),y=read();if(!q[x])
			{a[++n].x=x;a[n].y=y;q[x]=1;} mxn=max(mxn,y);
	}
	sort(a+1,a+n+1);if(a[n].x!=mx)a[++n].x=mx,a[n].y=0;
	rep(2,n,i)
	{
		int x1=a[i-1].x,y1=a[i-1].y,x2=a[i].x,y2=a[i].y;
		int r1=x1+y1,l2=x2-y2;int delta=l2-r1>>1;
		if(y2-y1==x2-x1)dp[i][0]=(dp[i-1][0]+(a[i-1].y?0:dp[i-1][1]))%Mod;
		else if(y1-y2==x2-x1)dp[i][1]=(dp[i-1][1]+dp[i-1][0])%Mod;
		else if(delta<0)dp[i][1]=(dp[i-1][0]+(a[i-1].y?0:dp[i-1][1]))%Mod;
		else if(!delta)dp[i][0]=(dp[i-1][0]+dp[i-1][1])%Mod,dp[i][1]=dp[i-1][0];
		else
		{
			if(a[i].y)dp[i][0]=(1ll*dp[i-1][1]*qpow(2,delta-1)%Mod+1ll*dp[i-1][0]*qpow(2,delta)%Mod)%Mod;
			dp[i][1]=(1ll*dp[i-1][1]*qpow(2,delta-1)%Mod+1ll*dp[i-1][0]*qpow(2,delta)%Mod)%Mod;
		}
		if(dp[i][1]||!a[i].y)mxn=max(mxn,x2-x1+y1+y2>>1);
	}
	printf("%lld %d",dp[n][1],mxn);
}
